#include <bits/stdc++.h>using namespace std;int main(){    int q;    cin >> q;    while (q--)    {        string s, t;        cin >> s >> t;        int n = s.size(), m = t.size();        bool f = 0;        for (int i = 0; i < n; i++)        {            if (s[i] != t[0])                continue;            for (int x = 0; x <= n - i - 1 && x < m; x++)            {                int l = m - x - 1;                if (l < 0 || i + x - l < 0)                    continue;                bool flag = 1;                for (int k = 0; k <= x; k++)                    if (s[i + k] != t[k])                     {                        flag = 0;                        break;                    }                if (!flag)                    continue;                for (int k = 1; k <= l; k++)                    if (s[i + x - k] != t[x + k])                    {                        flag = 0;                         break;                    }                if (flag)                {                    f = 1;                    break;                }            }            if (f)                break;        }        cout << (f ? "YES" : "NO") << "\n";    }    return 0;}